#include <stdio.h>
#include <string.h>

int isPalindrome(char *s) {
    int len = strlen(s);
    for (int i = 0; i < len / 2; i++) {
        if (s[i] != s[len - i - 1]) return 0;
    }
    return 1;
}

int palindromeness(char *s) {
    int len = strlen(s);
    if (len == 1) return 1;
    if (!isPalindrome(s)) return 0;
    char half[100005];
    strncpy(half, s, len / 2);
    half[len / 2] = '\0';
    return 1 + palindromeness(half);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[100005];
        scanf("%s", S);
        int sum = 0;
        for (int i = 0; i < strlen(S); i++) {
            for (int j = i; j < strlen(S); j++) {
                char sub[100005];
                strncpy(sub, S + i, j - i + 1);
                sub[j - i + 1] = '\0';
                if (isPalindrome(sub)) {
                    sum += palindromeness(sub);
                }
            }
        }
        printf("%d\n", sum);
    }
    return 0;
}

