int isPalindrome(string s) {
    int len = s.length();
    for (int i = 0; i < len / 2; i++) {
        if (s[i] != s[len - i - 1]) return 0;
    }
    return 1;
}

int palindromeness(string s) {
    int len = s.length();
    if (len == 1) return 1;
    if (!isPalindrome(s)) return 0;
    string half = s.substr(0, len / 2);
    return 1 + palindromeness(half);
}

