import sys

def is_palindrome(s):
    return s == s[::-1]


def palindromeness(s):
    if len(s) == 1:
        return 1
    if not is_palindrome(s):
        return 0
    half = s[:len(s) // 2]
    return 1 + palindromeness(half)

